// Minimal Chart.js-compatible API — no CDN needed
(function(global){
  function hexToRgb(hex){
    hex=hex.replace('#','');
    if(hex.length===3)hex=hex[0]+hex[0]+hex[1]+hex[1]+hex[2]+hex[2];
    const n=parseInt(hex,16);
    return{r:(n>>16)&255,g:(n>>8)&255,b:n&255};
  }
  function rgba(color,a){
    if(color.startsWith('rgba')||color.startsWith('rgb'))return color;
    const c=hexToRgb(color);
    return`rgba(${c.r},${c.g},${c.b},${a})`;
  }

  function Chart(canvas,config){
    this.canvas=canvas;
    this.config=config;
    this.ctx=canvas.getContext('2d');
    this._destroyed=false;
    const observer=new ResizeObserver(()=>this.draw());
    observer.observe(canvas.parentElement||canvas);
    this._observer=observer;
    setTimeout(()=>this.draw(),10);
  }

  Chart.defaults={font:{family:'DM Sans,system-ui,sans-serif',size:11},color:'#9ca3af',plugins:{legend:{display:false,position:'top',labels:{boxWidth:10}},tooltip:{boxPadding:4}}};

  Chart.prototype.destroy=function(){
    this._destroyed=true;
    if(this._observer)this._observer.disconnect();
  };

  Chart.prototype.draw=function(){
    if(this._destroyed)return;
    const c=this.config,t=c.type;
    if(t==='line')this.drawLine();
    else if(t==='doughnut')this.drawDonut();
    else if(t==='bar')this.drawBar();
  };

  Chart.prototype.drawLine=function(){
    const{ctx,canvas,config}=this;
    const{data,options={}}=config;
    const ds=data.datasets[0];
    const vals=ds.data;
    const labels=data.labels||[];
    const W=canvas.parentElement?canvas.parentElement.clientWidth||300:300;
    const H=canvas.parentElement?canvas.parentElement.clientHeight||200:200;
    canvas.width=W*window.devicePixelRatio||W;
    canvas.height=H*window.devicePixelRatio||H;
    canvas.style.width=W+'px'; canvas.style.height=H+'px';
    ctx.scale(window.devicePixelRatio||1,window.devicePixelRatio||1);
    ctx.clearRect(0,0,W,H);

    const pad={top:10,right:10,bottom:30,left:44};
    const cW=W-pad.left-pad.right, cH=H-pad.top-pad.bottom;
    const min=Math.min(...vals)*0.98, max=Math.max(...vals)*1.02;
    const range=max-min||1;

    const px=i=>pad.left+i/(vals.length-1)*cW;
    const py=v=>pad.top+cH-(v-min)/range*cH;

    // Grid lines
    const isDark=document.documentElement.matches&&document.body.style.background==='#060d19';
    ctx.strokeStyle='rgba(0,0,0,0.05)'; ctx.lineWidth=1;
    for(let i=0;i<=4;i++){
      const y=pad.top+i*cH/4;
      ctx.beginPath(); ctx.moveTo(pad.left,y); ctx.lineTo(pad.left+cW,y); ctx.stroke();
    }

    // Y axis labels
    ctx.fillStyle='#9ca3af'; ctx.font=`10px DM Sans,system-ui,sans-serif`; ctx.textAlign='right';
    for(let i=0;i<=4;i++){
      const v=max-(i/4)*range;
      const y=pad.top+i*cH/4;
      const lbl=v>=100000?'₹'+(v/1000).toFixed(0)+'k':'₹'+v.toFixed(0);
      ctx.fillText(lbl,pad.left-4,y+3);
    }

    // X axis labels
    ctx.textAlign='center';
    const step=Math.ceil(labels.length/7);
    labels.forEach((l,i)=>{
      if(i%step===0||i===labels.length-1){
        ctx.fillText(l,px(i),H-pad.bottom+14);
      }
    });

    // Fill
    ctx.beginPath();
    ctx.moveTo(px(0),py(vals[0]));
    for(let i=1;i<vals.length;i++){
      const x0=px(i-1),y0=py(vals[i-1]),x1=px(i),y1=py(vals[i]);
      const cx=(x0+x1)/2;
      ctx.bezierCurveTo(cx,y0,cx,y1,x1,y1);
    }
    ctx.lineTo(px(vals.length-1),pad.top+cH);
    ctx.lineTo(px(0),pad.top+cH);
    ctx.closePath();
    const grad=ctx.createLinearGradient(0,pad.top,0,pad.top+cH);
    const col=ds.borderColor||'#1a6b5a';
    grad.addColorStop(0,rgba(col,0.15));
    grad.addColorStop(1,rgba(col,0.01));
    ctx.fillStyle=grad; ctx.fill();

    // Line
    ctx.beginPath();
    ctx.moveTo(px(0),py(vals[0]));
    for(let i=1;i<vals.length;i++){
      const x0=px(i-1),y0=py(vals[i-1]),x1=px(i),y1=py(vals[i]);
      const cx=(x0+x1)/2;
      ctx.bezierCurveTo(cx,y0,cx,y1,x1,y1);
    }
    ctx.strokeStyle=col; ctx.lineWidth=2.5; ctx.stroke();

    // Last point dot
    ctx.beginPath();
    ctx.arc(px(vals.length-1),py(vals[vals.length-1]),5,0,Math.PI*2);
    ctx.fillStyle=col; ctx.fill();
    ctx.strokeStyle='white'; ctx.lineWidth=2; ctx.stroke();
  };

  Chart.prototype.drawDonut=function(){
    const{ctx,canvas,config}=this;
    const{data}=config;
    const ds=data.datasets[0];
    const vals=ds.data, colors=ds.backgroundColor||[];
    const W=canvas.parentElement?canvas.parentElement.clientWidth||200:200;
    const H=canvas.parentElement?canvas.parentElement.clientHeight||160:160;
    canvas.width=W*(window.devicePixelRatio||1);
    canvas.height=H*(window.devicePixelRatio||1);
    canvas.style.width=W+'px'; canvas.style.height=H+'px';
    ctx.scale(window.devicePixelRatio||1,window.devicePixelRatio||1);
    ctx.clearRect(0,0,W,H);

    const total=vals.reduce((a,b)=>a+b,0);
    const cx=W/2, cy=H/2;
    const r=Math.min(cx,cy)-12;
    const cut=r*0.72;
    let angle=-Math.PI/2;

    vals.forEach((v,i)=>{
      const sweep=v/total*Math.PI*2;
      ctx.beginPath();
      ctx.moveTo(cx,cy);
      ctx.arc(cx,cy,r,angle,angle+sweep);
      ctx.closePath();
      ctx.fillStyle=colors[i]||'#ccc';
      ctx.fill();
      angle+=sweep;
    });

    // Cutout
    ctx.beginPath();
    ctx.arc(cx,cy,cut,0,Math.PI*2);
    const bg=getComputedStyle(document.documentElement).getPropertyValue('--surface').trim()||'#fff';
    ctx.fillStyle=bg; ctx.fill();

    // Center text
    ctx.fillStyle='#475569'; ctx.font=`bold 13px DM Sans,system-ui,sans-serif`;
    ctx.textAlign='center'; ctx.textBaseline='middle';
    ctx.fillText(vals[0]+'%',cx,cy);
  };

  Chart.prototype.drawBar=function(){
    const{ctx,canvas,config}=this;
    const{data,options={}}=config;
    const labels=data.labels||[];
    const ds=data.datasets[0];
    const vals=ds.data||[];
    const colors=Array.isArray(ds.backgroundColor)?ds.backgroundColor:new Array(vals.length).fill(ds.backgroundColor||'#1a6b5a');

    const W=canvas.parentElement?canvas.parentElement.clientWidth||300:300;
    const H=canvas.parentElement?canvas.parentElement.clientHeight||180:180;
    canvas.width=W*(window.devicePixelRatio||1);
    canvas.height=H*(window.devicePixelRatio||1);
    canvas.style.width=W+'px'; canvas.style.height=H+'px';
    ctx.scale(window.devicePixelRatio||1,window.devicePixelRatio||1);
    ctx.clearRect(0,0,W,H);

    const pad={top:10,right:10,bottom:30,left:36};
    const cW=W-pad.left-pad.right, cH=H-pad.top-pad.bottom;
    const max=Math.max(...vals)*1.1||1;
    const bw=cW/vals.length*0.55;
    const gap=cW/vals.length;

    // Grid
    ctx.strokeStyle='rgba(0,0,0,0.05)'; ctx.lineWidth=1;
    for(let i=0;i<=3;i++){
      const y=pad.top+i*cH/3;
      ctx.beginPath(); ctx.moveTo(pad.left,y); ctx.lineTo(pad.left+cW,y); ctx.stroke();
      ctx.fillStyle='#9ca3af'; ctx.font='10px DM Sans,system-ui,sans-serif'; ctx.textAlign='right';
      ctx.fillText((max-i*max/3).toFixed(0)+'%',pad.left-3,y+3);
    }

    vals.forEach((v,i)=>{
      const x=pad.left+i*gap+(gap-bw)/2;
      const bh=v/max*cH;
      const y=pad.top+cH-bh;
      const r=Math.min(6,bw/2);
      ctx.beginPath();
      ctx.moveTo(x+r,y); ctx.lineTo(x+bw-r,y);
      ctx.arcTo(x+bw,y,x+bw,y+r,r);
      ctx.lineTo(x+bw,y+bh); ctx.lineTo(x,y+bh);
      ctx.arcTo(x,y,x+r,y,r);
      ctx.closePath();
      ctx.fillStyle=colors[i]||'#1a6b5a'; ctx.fill();

      ctx.fillStyle='#475569'; ctx.font='10px DM Sans,system-ui,sans-serif'; ctx.textAlign='center';
      const lbl=labels[i]||'';
      ctx.fillText(lbl.length>9?lbl.slice(0,9)+'…':lbl,x+bw/2,H-pad.bottom+14);
    });
  };

  global.Chart=Chart;
})(window);
